/// <summary>
/// Q8: ValidateBST
/// Task: Determine whether a given binary tree is a valid Binary Search Tree (BST)
/// using multiple approaches:
/// 1. Inorder traversal should produce a sorted sequence (O(n) time, O(n) space)
/// 2. Recursive validation with min/max bounds (O(n) time, O(h) space, optimal)
/// 3. Iterative inorder traversal with previous value check (O(n) time, O(h) space)
/// </summary>
public class ValidateBST
{
    private TreeNode? _root;

    public ValidateBST(TreeNode? root)
    {
        _root = root;
    }

    // 1️. Inorder Traversal + Check Sorted
    // - Perform full inorder traversal, store results
    // - Verify the resulting list is strictly ascending
    // Time: O(n), Space: O(n)
    public bool IsValidWithInorderList()
    {
        List<int> values = new List<int>();
        InorderCollect(_root, values);

        for (int i = 1; i < values.Count; i++)
        {
            if (values[i] <= values[i - 1])
                return false;
        }

        return true;
    }

    private void InorderCollect(TreeNode? node, List<int> values)
    {
        if (node == null) return;
        InorderCollect(node.Left, values);
        values.Add(node.Value);
        InorderCollect(node.Right, values);
    }

    // 2️. Recursive with Min/Max Bounds (Optimal)
    // - Each node must be within a valid range
    // - Left child: upper bound is parent value
    // - Right child: lower bound is parent value
    // Time: O(n), Space: O(h)
    public bool IsValidRecursive()
    {
        return IsValidHelper(_root, long.MinValue, long.MaxValue);
    }

    private bool IsValidHelper(TreeNode? node, long min, long max)
    {
        if (node == null) return true;

        if (node.Value <= min || node.Value >= max)
            return false;

        return IsValidHelper(node.Left, min, node.Value)
            && IsValidHelper(node.Right, node.Value, max);
    }

    // 3️. Iterative Inorder with Previous Value
    // - Perform inorder traversal iteratively
    // - Check that each value is greater than the previous one
    // Time: O(n), Space: O(h)
    public bool IsValidIterative()
    {
        Stack<TreeNode> stack = new Stack<TreeNode>();
        TreeNode? current = _root;
        long previous = long.MinValue;

        while (current != null || stack.Count > 0)
        {
            while (current != null)
            {
                stack.Push(current);
                current = current.Left;
            }

            current = stack.Pop();

            if (current.Value <= previous)
                return false;

            previous = current.Value;
            current = current.Right;
        }

        return true;
    }
}

**Approach:** Iterate every cell; when you hit unvisited land, increment the count and flood-fill (DFS/BFS) the whole island, sinking visited land to '0' so it isn't counted again.

```csharp
public int NumIslands(char[][] grid) {
    if (grid is null || grid.Length == 0) return 0;
    int rows = grid.Length, cols = grid[0].Length, count = 0;
    void Sink(int r, int c) {
        if (r < 0 || c < 0 || r >= rows || c >= cols || grid[r][c] != '1') return;
        grid[r][c] = '0';
        Sink(r + 1, c); Sink(r - 1, c); Sink(r, c + 1); Sink(r, c - 1);
    }
    for (int r = 0; r < rows; r++)
        for (int c = 0; c < cols; c++)
            if (grid[r][c] == '1') { count++; Sink(r, c); }
    return count;
}
```

**Complexity:** O(rows·cols) time, O(rows·cols) worst-case recursion stack (use an explicit stack/queue to avoid stack overflow on huge grids).

**Approach:** This is cycle detection in a directed graph, solved with Kahn's topological sort (BFS on in-degrees). If you can order all nodes, there's no cycle.

```csharp
public bool CanFinish(int numCourses, int[][] prerequisites) {
    var adj = new List<int>[numCourses];
    for (int i = 0; i < numCourses; i++) adj[i] = new List<int>();
    var indeg = new int[numCourses];
    foreach (var p in prerequisites) { adj[p[1]].Add(p[0]); indeg[p[0]]++; }
    var q = new Queue<int>();
    for (int i = 0; i < numCourses; i++) if (indeg[i] == 0) q.Enqueue(i);
    int taken = 0;
    while (q.Count > 0) {
        int cur = q.Dequeue(); taken++;
        foreach (var nxt in adj[cur]) if (--indeg[nxt] == 0) q.Enqueue(nxt);
    }
    return taken == numCourses;
}
```

**Complexity:** O(V + E) time and space. A DFS with a recursion-stack (gray/black) coloring is an equally valid cycle-detection alternative.

**Approach:** DFS/BFS while keeping a dictionary mapping original node -> its clone, so each node is cloned exactly once and cycles don't cause infinite recursion.

```csharp
public Node CloneGraph(Node node) {
    if (node is null) return null;
    var map = new Dictionary<Node, Node>();
    Node Dfs(Node n) {
        if (map.TryGetValue(n, out var existing)) return existing;
        var copy = new Node(n.val);
        map[n] = copy;
        foreach (var nb in n.neighbors) copy.neighbors.Add(Dfs(nb));
        return copy;
    }
    return Dfs(node);
}
```

**Complexity:** O(V + E) time, O(V) space for the map. The map is the key: it both prevents re-cloning and breaks cycles.

**Approach:** Greedily expand the closest unsettled node using a min-priority queue. .NET's `PriorityQueue<TElement,TPriority>` (available since .NET 6) makes this clean.

```csharp
// graph[u] = list of (to, weight)
public int[] Dijkstra(List<(int to, int w)>[] graph, int src) {
    int n = graph.Length;
    var dist = new int[n];
    Array.Fill(dist, int.MaxValue);
    dist[src] = 0;
    var pq = new PriorityQueue<int, int>(); // node, distance
    pq.Enqueue(src, 0);
    while (pq.TryDequeue(out int u, out int d)) {
        if (d > dist[u]) continue;            // stale entry
        foreach (var (v, w) in graph[u]) {
            int nd = d + w;
            if (nd < dist[v]) { dist[v] = nd; pq.Enqueue(v, nd); }
        }
    }
    return dist;
}
```

**Complexity:** O((V + E) log V). Note Dijkstra requires non-negative weights; for negative edges use Bellman-Ford.

**Approach:** Start with n components; for each edge, union the two endpoints. Each successful union reduces the component count by one. Use path compression + union by rank for near-O(1) operations.

```csharp
public int CountComponents(int n, int[][] edges) {
    var parent = new int[n];
    var rank = new int[n];
    for (int i = 0; i < n; i++) parent[i] = i;
    int Find(int x) { while (parent[x] != x) { parent[x] = parent[parent[x]]; x = parent[x]; } return x; }
    int components = n;
    foreach (var e in edges) {
        int a = Find(e[0]), b = Find(e[1]);
        if (a == b) continue;
        if (rank[a] < rank[b]) (a, b) = (b, a);
        parent[b] = a;
        if (rank[a] == rank[b]) rank[a]++;
        components--;
    }
    return components;
}
```

**Complexity:** O(E·α(n)) ≈ near-linear time, O(n) space. A DFS/BFS visited-set approach is also acceptable.

**Approach:** This is an unweighted shortest-path problem -> BFS. Each word is a node; neighbors are words differing by one letter. Use a HashSet for O(1) membership and remove visited words to avoid revisiting.

```csharp
public int LadderLength(string beginWord, string endWord, IList<string> wordList) {
    var dict = new HashSet<string>(wordList);
    if (!dict.Contains(endWord)) return 0;
    var q = new Queue<string>();
    q.Enqueue(beginWord);
    int steps = 1;
    while (q.Count > 0) {
        for (int size = q.Count; size > 0; size--) {
            var word = q.Dequeue().ToCharArray();
            for (int i = 0; i < word.Length; i++) {
                char original = word[i];
                for (char c = 'a'; c <= 'z'; c++) {
                    word[i] = c;
                    var candidate = new string(word);
                    if (candidate == endWord) return steps + 1;
                    if (dict.Remove(candidate)) q.Enqueue(candidate);
                }
                word[i] = original;
            }
        }
        steps++;
    }
    return 0;
}
```

**Complexity:** O(N·L·26) where N = words, L = word length. BFS guarantees the first time we reach endWord is the shortest path.

**Approach:** Push opening brackets onto a stack; on a closing bracket, the top of the stack must be its matching opener. The string is valid only if every closer matches and the stack ends empty.

```csharp
public bool IsValid(string s) {
    var stack = new Stack<char>();
    var pairs = new Dictionary<char, char> { [')'] = '(', [']'] = '[', ['}'] = '{' };
    foreach (var c in s) {
        if (pairs.ContainsValue(c)) stack.Push(c);
        else if (pairs.TryGetValue(c, out var open)) {
            if (stack.Count == 0 || stack.Pop() != open) return false;
        }
    }
    return stack.Count == 0;
}
```

**Complexity:** O(n) time, O(n) space. The classic 'matching pairs' use case for a stack (LIFO).

**Approach:** Keep an auxiliary stack that tracks the minimum at each level (or store pairs of value+current-min). Each push records the running minimum so GetMin is a constant-time peek.

```csharp
public class MinStack {
    private readonly Stack<(int val, int min)> _s = new();
    public void Push(int x) {
        int min = _s.Count == 0 ? x : Math.Min(x, _s.Peek().min);
        _s.Push((x, min));
    }
    public void Pop() => _s.Pop();
    public int Top() => _s.Peek().val;
    public int GetMin() => _s.Peek().min;
}
```

**Complexity:** O(1) for every operation, O(n) space. Storing the min alongside each element is what keeps GetMin constant even after pops.

**Approach:** Use an 'in' stack for pushes and an 'out' stack for pops. When 'out' is empty, pour 'in' into 'out', which reverses the order so the oldest element ends up on top.

```csharp
public class MyQueue {
    private readonly Stack<int> _in = new();
    private readonly Stack<int> _out = new();
    public void Enqueue(int x) => _in.Push(x);
    private void Shift() { if (_out.Count == 0) while (_in.Count > 0) _out.Push(_in.Pop()); }
    public int Dequeue() { Shift(); return _out.Pop(); }
    public int Peek() { Shift(); return _out.Peek(); }
    public bool Empty() => _in.Count == 0 && _out.Count == 0;
}
```

**Complexity:** Each element is moved at most once between stacks, so Dequeue/Peek are amortized O(1); Enqueue is O(1).

**Approach:** Use a monotonic decreasing stack of indices. When the current day is warmer than the day on top of the stack, that day's answer is the index difference; pop and repeat.

```csharp
public int[] DailyTemperatures(int[] temps) {
    int n = temps.Length;
    var res = new int[n];
    var stack = new Stack<int>(); // indices of unresolved days
    for (int i = 0; i < n; i++) {
        while (stack.Count > 0 && temps[i] > temps[stack.Peek()]) {
            int prev = stack.Pop();
            res[prev] = i - prev;
        }
        stack.Push(i);
    }
    return res;
}
```

**Complexity:** O(n) time (each index pushed/popped once), O(n) space. Monotonic stacks are the go-to for 'next greater element' style problems.

**Approach:** Count frequencies in a dictionary, then keep a min-heap of size k by frequency: push each (element, frequency); when the heap exceeds k, drop the smallest. What remains is the top k.

```csharp
public int[] TopKFrequent(int[] nums, int k) {
    var freq = new Dictionary<int, int>();
    foreach (var n in nums) freq[n] = freq.GetValueOrDefault(n) + 1;
    var heap = new PriorityQueue<int, int>(); // element, frequency (min-heap)
    foreach (var kv in freq) {
        heap.Enqueue(kv.Key, kv.Value);
        if (heap.Count > k) heap.Dequeue();
    }
    var res = new int[k];
    for (int i = k - 1; i >= 0; i--) res[i] = heap.Dequeue();
    return res;
}
```

**Complexity:** O(n log k) time, O(n) space. Bucket sort by frequency can push this to O(n) if needed.

**Approach:** Maintain two heaps: a max-heap `_lo` for the lower half and a min-heap `_hi` for the upper half, kept balanced so `_lo.Count >= _hi.Count` and they differ by at most 1. Push to `_lo`, move its max to `_hi`, then if `_hi` grew larger move its min back — this keeps the median at the top of `_lo`.

```csharp
public class MedianFinder {
    private readonly PriorityQueue<int, int> _lo = new(); // max-heap: priority = -value
    private readonly PriorityQueue<int, int> _hi = new(); // min-heap: priority =  value
    public void AddNum(int num) {
        _lo.Enqueue(num, -num);
        int top = _lo.Dequeue();
        _hi.Enqueue(top, top);
        if (_hi.Count > _lo.Count) {
            int x = _hi.Dequeue();
            _lo.Enqueue(x, -x);
        }
    }
    public double FindMedian() =>
        _lo.Count > _hi.Count ? _lo.Peek() : (_lo.Peek() + _hi.Peek()) / 2.0;
}
```

**Complexity:** AddNum is O(log n), FindMedian is O(1).

**Approach:** One pass with a hash map of value -> index. For each number, check whether its complement (target - num) has already been seen; if so you have the pair.

```csharp
public int[] TwoSum(int[] nums, int target) {
    var seen = new Dictionary<int, int>();
    for (int i = 0; i < nums.Length; i++) {
        int need = target - nums[i];
        if (seen.TryGetValue(need, out int j)) return new[] { j, i };
        seen[nums[i]] = i;
    }
    return Array.Empty<int>();
}
```

**Complexity:** O(n) time, O(n) space — the hash map turns the brute-force O(n²) into a single pass.

**Approach:** Two anagrams share the same sorted characters, so use the sorted string as a dictionary key and bucket each word under it.

```csharp
public IList<IList<string>> GroupAnagrams(string[] strs) {
    var map = new Dictionary<string, IList<string>>();
    foreach (var s in strs) {
        var chars = s.ToCharArray();
        Array.Sort(chars);
        var key = new string(chars);
        if (!map.TryGetValue(key, out var bucket)) map[key] = bucket = new List<string>();
        bucket.Add(s);
    }
    return map.Values.ToList();
}
```

**Complexity:** O(n·k log k) where k is the max word length (sorting each word). A character-count key (e.g. a 26-length signature) brings it to O(n·k).

**Approach:** Sliding window with a hash map of char -> last index. Expand the right edge; when you hit a repeat inside the window, jump the left edge past the previous occurrence.

```csharp
public int LengthOfLongestSubstring(string s) {
    var lastSeen = new Dictionary<char, int>();
    int left = 0, best = 0;
    for (int right = 0; right < s.Length; right++) {
        char c = s[right];
        if (lastSeen.TryGetValue(c, out int idx) && idx >= left)
            left = idx + 1;
        lastSeen[c] = right;
        best = Math.Max(best, right - left + 1);
    }
    return best;
}
```

**Complexity:** O(n) time, O(min(n, charset)) space. The window never moves backward, so each character is visited at most twice.

**Approach:** Count each character's frequency in one pass, then scan again and return the index of the first character with a count of 1.

```csharp
public int FirstUniqChar(string s) {
    var counts = new Dictionary<char, int>();
    foreach (var c in s) counts[c] = counts.GetValueOrDefault(c) + 1;
    for (int i = 0; i < s.Length; i++)
        if (counts[s[i]] == 1) return i;
    return -1;
}
```

**Complexity:** O(n) time, O(1) space if the alphabet is fixed (e.g. 26 lowercase letters). Two passes, but both linear.

**Approach:** Expand around each center. There are 2n-1 centers (each character and each gap between characters); for each, grow outward while characters match and track the longest span.

```csharp
public string LongestPalindrome(string s) {
    if (string.IsNullOrEmpty(s)) return "";
    int start = 0, maxLen = 1;
    int Expand(int l, int r) {
        while (l >= 0 && r < s.Length && s[l] == s[r]) { l--; r++; }
        return r - l - 1;
    }
    for (int i = 0; i < s.Length; i++) {
        int len = Math.Max(Expand(i, i), Expand(i, i + 1));
        if (len > maxLen) { maxLen = len; start = i - (len - 1) / 2; }
    }
    return s.Substring(start, maxLen);
}
```

**Complexity:** O(n²) time, O(1) space. Manacher's algorithm solves it in O(n) but expand-around-center is the expected interview answer.

**Approach:** Combine a hash map (key -> node) for O(1) lookup with a doubly linked list ordered by recency. Get/Put move the node to the front (most recent); eviction removes the tail. In C#, `LinkedList<T>` + `Dictionary` gives this directly.

```csharp
public class LRUCache {
    private readonly int _cap;
    private readonly Dictionary<int, LinkedListNode<(int key, int val)>> _map = new();
    private readonly LinkedList<(int key, int val)> _list = new();
    public LRUCache(int capacity) => _cap = capacity;
    public int Get(int key) {
        if (!_map.TryGetValue(key, out var node)) return -1;
        _list.Remove(node); _list.AddFirst(node);
        return node.Value.val;
    }
    public void Put(int key, int value) {
        if (_map.TryGetValue(key, out var node)) { _list.Remove(node); }
        else if (_map.Count >= _cap) {
            var lru = _list.Last; _list.RemoveLast(); _map.Remove(lru.Value.key);
        }
        var fresh = new LinkedListNode<(int, int)>((key, value));
        _list.AddFirst(fresh); _map[key] = fresh;
    }
}
```

**Complexity:** O(1) for Get and Put. The doubly linked list gives O(1) move/remove; the map gives O(1) lookup.

**Approach:** Walk the list with three pointers (prev, cur, next), flipping each node's `next` to point backward. `prev` ends at the new head.

```csharp
public ListNode Reverse(ListNode head) {
    ListNode prev = null, cur = head;
    while (cur != null) {
        var next = cur.next;
        cur.next = prev;
        prev = cur;
        cur = next;
    }
    return prev;
}
```

**Complexity:** O(n) time, O(1) space. The recursive version is O(n) space due to the call stack — interviewers usually want the iterative O(1) one.

**Approach:** Floyd's tortoise-and-hare: advance one pointer by 1 and another by 2. If they ever meet, there's a cycle; if the fast pointer reaches null, there isn't.

```csharp
public bool HasCycle(ListNode head) {
    ListNode slow = head, fast = head;
    while (fast != null && fast.next != null) {
        slow = slow.next;
        fast = fast.next.next;
        if (slow == fast) return true;
    }
    return false;
}
```

**Complexity:** O(n) time, O(1) space. A HashSet of visited nodes also works but uses O(n) space — Floyd's is the preferred answer.

**Approach:** Use a dummy head and a tail pointer; repeatedly attach the smaller of the two current nodes, then append whatever remains.

```csharp
public ListNode MergeTwoLists(ListNode a, ListNode b) {
    var dummy = new ListNode(0);
    var tail = dummy;
    while (a != null && b != null) {
        if (a.val <= b.val) { tail.next = a; a = a.next; }
        else { tail.next = b; b = b.next; }
        tail = tail.next;
    }
    tail.next = a ?? b;
    return dummy.next;
}
```

**Complexity:** O(n + m) time, O(1) extra space. The dummy node avoids special-casing the head.

**Approach:** Backtracking: at each index decide to include or skip the element, recording the current combination at every node of the decision tree.

```csharp
public IList<IList<int>> Subsets(int[] nums) {
    var res = new List<IList<int>>();
    void Backtrack(int start, List<int> path) {
        res.Add(new List<int>(path));      // snapshot current subset
        for (int i = start; i < nums.Length; i++) {
            path.Add(nums[i]);
            Backtrack(i + 1, path);
            path.RemoveAt(path.Count - 1); // undo choice
        }
    }
    Backtrack(0, new List<int>());
    return res;
}
```

**Complexity:** O(n·2^n) — there are 2^n subsets and copying each costs up to O(n). This 'choose / explore / un-choose' template covers permutations, combinations, and N-Queens too.

**Approach:** Bottom-up DP. `dp[a]` = min coins to make amount `a`. For each amount, try every coin and take the best sub-result plus one coin.

```csharp
public int CoinChange(int[] coins, int amount) {
    var dp = new int[amount + 1];
    Array.Fill(dp, amount + 1);   // 'infinity' sentinel
    dp[0] = 0;
    for (int a = 1; a <= amount; a++)
        foreach (var c in coins)
            if (c <= a) dp[a] = Math.Min(dp[a], dp[a - c] + 1);
    return dp[amount] > amount ? -1 : dp[amount];
}
```

**Complexity:** O(amount·coins) time, O(amount) space. This is the canonical unbounded-knapsack-style DP.

**Approach:** 2D DP. `dp[i,j]` = LCS length of the first i chars of a and first j of b. If the characters match, extend the diagonal; otherwise take the best of dropping one character from either string.

```csharp
public int LongestCommonSubsequence(string a, string b) {
    int m = a.Length, n = b.Length;
    var dp = new int[m + 1, n + 1];
    for (int i = 1; i <= m; i++)
        for (int j = 1; j <= n; j++)
            dp[i, j] = a[i - 1] == b[j - 1]
                ? dp[i - 1, j - 1] + 1
                : Math.Max(dp[i - 1, j], dp[i, j - 1]);
    return dp[m, n];
}
```

**Complexity:** O(m·n) time and space (space can be reduced to O(min(m,n)) with a rolling row). LCS underpins diff tools and bioinformatics alignment.

**Approach:** Push numbers onto a stack; when you hit an operator, pop the two most recent operands, apply it, and push the result. The final stack value is the answer.

```csharp
public int EvalRPN(string[] tokens) {
    var st = new Stack<int>();
    foreach (var t in tokens) {
        if (t is "+" or "-" or "*" or "/") {
            int b = st.Pop(), a = st.Pop();
            st.Push(t switch { "+" => a + b, "-" => a - b, "*" => a * b, _ => a / b });
        } else st.Push(int.Parse(t));
    }
    return st.Pop();
}
```

**Complexity:** O(n) time, O(n) space. Postfix evaluation is the textbook stack use case (no operator precedence needed).

**Approach:** Keep a double-ended queue of indices whose values are in decreasing order. Before adding a new index, pop smaller values from the back (they can never be the max while the new one is in range); pop the front when it leaves the window. The front is always the current window max.

```csharp
public int[] MaxSlidingWindow(int[] nums, int k) {
    var dq = new LinkedList<int>(); // indices, values decreasing
    var res = new int[nums.Length - k + 1];
    for (int i = 0; i < nums.Length; i++) {
        if (dq.Count > 0 && dq.First.Value <= i - k) dq.RemoveFirst();
        while (dq.Count > 0 && nums[dq.Last.Value] <= nums[i]) dq.RemoveLast();
        dq.AddLast(i);
        if (i >= k - 1) res[i - k + 1] = nums[dq.First.Value];
    }
    return res;
}
```

**Complexity:** O(n) time (each index enters/leaves the deque once), O(k) space. A naive recompute is O(n·k); the monotonic deque is the optimal answer.

**Approach:** Use a fixed array with head and count (or head/tail) indices that wrap with modulo. Tracking a count distinguishes full from empty cleanly.

```csharp
public class MyCircularQueue {
    private readonly int[] _buf;
    private int _head, _count;
    public MyCircularQueue(int k) => _buf = new int[k];
    public bool EnQueue(int v) {
        if (IsFull()) return false;
        _buf[(_head + _count) % _buf.Length] = v; _count++; return true;
    }
    public bool DeQueue() {
        if (IsEmpty()) return false;
        _head = (_head + 1) % _buf.Length; _count--; return true;
    }
    public int Front() => IsEmpty() ? -1 : _buf[_head];
    public int Rear()  => IsEmpty() ? -1 : _buf[(_head + _count - 1) % _buf.Length];
    public bool IsEmpty() => _count == 0;
    public bool IsFull()  => _count == _buf.Length;
}
```

**Complexity:** O(1) per operation, O(k) space. Modulo arithmetic is what makes the buffer 'circular' without shifting elements.

**Approach:** Keep a queue of timestamps. On each ping, enqueue t and dequeue everything older than t-3000; the queue size is the answer. The window only moves forward, so old entries are removed once and never revisited.

```csharp
public class RecentCounter {
    private readonly Queue<int> _q = new();
    public int Ping(int t) {
        _q.Enqueue(t);
        while (_q.Peek() < t - 3000) _q.Dequeue();
        return _q.Count;
    }
}
```

**Complexity:** Amortized O(1) per ping (each timestamp is enqueued and dequeued at most once). A queue is the natural fit for a sliding time window.

**Approach:** Maintain a min-heap of size k. Push each number; once the heap exceeds k, pop the smallest. After processing all numbers, the heap's root is the kth largest.

```csharp
public int FindKthLargest(int[] nums, int k) {
    var heap = new PriorityQueue<int, int>(); // min-heap
    foreach (var n in nums) {
        heap.Enqueue(n, n);
        if (heap.Count > k) heap.Dequeue();
    }
    return heap.Peek();
}
```

**Complexity:** O(n log k) time, O(k) space. Quickselect achieves O(n) average but the heap solution is simpler and streaming-friendly.

**Approach:** Use a min-heap keyed by node value, seeded with each list's head. Repeatedly pop the smallest node, append it to the result, and push that node's next. This always emits the global minimum among the list fronts.

```csharp
public ListNode MergeKLists(ListNode[] lists) {
    var heap = new PriorityQueue<ListNode, int>();
    foreach (var node in lists) if (node != null) heap.Enqueue(node, node.val);
    var dummy = new ListNode(0); var tail = dummy;
    while (heap.Count > 0) {
        var node = heap.Dequeue();
        tail.next = node; tail = node;
        if (node.next != null) heap.Enqueue(node.next, node.next.val);
    }
    return dummy.next;
}
```

**Complexity:** O(N log k) time where N is the total number of nodes, O(k) heap space. The heap keeps only k candidates at a time instead of all N.

**Approach:** Anagrams have identical character counts. Tally counts from s and subtract using t; if lengths differ or any count goes negative / nonzero, it's not an anagram. For lowercase ASCII a fixed 26-int array is fastest.

```csharp
public bool IsAnagram(string s, string t) {
    if (s.Length != t.Length) return false;
    var counts = new int[26];
    foreach (var c in s) counts[c - 'a']++;
    foreach (var c in t) if (--counts[c - 'a'] < 0) return false;
    return true;
}
```

**Complexity:** O(n) time, O(1) space (fixed alphabet). For full Unicode, use a Dictionary<char,int> instead of the 26-slot array.

**Approach:** Two pointers from both ends moving inward, skipping non-alphanumeric characters and comparing case-insensitively. No extra string allocation needed.

```csharp
public bool IsPalindrome(string s) {
    int l = 0, r = s.Length - 1;
    while (l < r) {
        while (l < r && !char.IsLetterOrDigit(s[l])) l++;
        while (l < r && !char.IsLetterOrDigit(s[r])) r--;
        if (char.ToLowerInvariant(s[l]) != char.ToLowerInvariant(s[r])) return false;
        l++; r--;
    }
    return true;
}
```

**Complexity:** O(n) time, O(1) space. The two-pointer scan avoids building a cleaned copy of the string.

**Approach:** Two pointers with a dummy head. Advance a 'fast' pointer n steps ahead, then move both until fast reaches the end; 'slow' now sits just before the target, so you can unlink it in a single pass.

```csharp
public ListNode RemoveNthFromEnd(ListNode head, int n) {
    var dummy = new ListNode(0) { next = head };
    ListNode fast = dummy, slow = dummy;
    for (int i = 0; i < n; i++) fast = fast.next;
    while (fast.next != null) { fast = fast.next; slow = slow.next; }
    slow.next = slow.next.next;
    return dummy.next;
}
```

**Complexity:** O(n) time, O(1) space — one pass. The dummy node handles the edge case of removing the head cleanly.

**Approach:** Backtracking. Build a permutation by picking each unused element in turn, recursing, then undoing the choice. A boolean 'used' array (or swapping in place) tracks what's already in the current path.

```csharp
public IList<IList<int>> Permute(int[] nums) {
    var res = new List<IList<int>>();
    var used = new bool[nums.Length];
    void Backtrack(List<int> path) {
        if (path.Count == nums.Length) { res.Add(new List<int>(path)); return; }
        for (int i = 0; i < nums.Length; i++) {
            if (used[i]) continue;
            used[i] = true; path.Add(nums[i]);
            Backtrack(path);
            path.RemoveAt(path.Count - 1); used[i] = false;
        }
    }
    Backtrack(new List<int>());
    return res;
}
```

**Complexity:** O(n·n!) — there are n! permutations and copying each costs O(n). Same choose/explore/undo template as subsets and combinations.

**Approach:** Backtracking with two counters. You may add '(' while open < n, and add ')' while close < open (so it never becomes invalid). Record a result when the string reaches length 2n.

```csharp
public IList<string> GenerateParenthesis(int n) {
    var res = new List<string>();
    void Backtrack(System.Text.StringBuilder sb, int open, int close) {
        if (sb.Length == 2 * n) { res.Add(sb.ToString()); return; }
        if (open < n)    { sb.Append('('); Backtrack(sb, open + 1, close); sb.Length--; }
        if (close < open){ sb.Append(')'); Backtrack(sb, open, close + 1); sb.Length--; }
    }
    Backtrack(new System.Text.StringBuilder(), 0, 0);
    return res;
}
```

**Complexity:** O(4^n / sqrt(n)) (the nth Catalan number) results. The 'close < open' constraint prunes invalid branches early instead of generating then filtering.

**Approach:** Backtracking. Try each candidate from a start index (to avoid duplicate combinations); recurse allowing reuse by keeping the same index, and prune when the remaining target goes negative.

```csharp
public IList<IList<int>> CombinationSum(int[] candidates, int target) {
    var res = new List<IList<int>>();
    void Backtrack(int start, int remain, List<int> path) {
        if (remain == 0) { res.Add(new List<int>(path)); return; }
        for (int i = start; i < candidates.Length; i++) {
            if (candidates[i] > remain) continue;
            path.Add(candidates[i]);
            Backtrack(i, remain - candidates[i], path); // i (not i+1) allows reuse
            path.RemoveAt(path.Count - 1);
        }
    }
    Backtrack(0, target, new List<int>());
    return res;
}
```

**Complexity:** Exponential in the worst case; the start index prevents permutations of the same set from being counted twice.

**Approach:** The ways to reach step n equal the ways to reach n-1 plus n-2 (your last move was 1 or 2 steps) — the Fibonacci recurrence. Compute bottom-up with two rolling variables instead of recursion.

```csharp
public int ClimbStairs(int n) {
    if (n <= 2) return n;
    int prev = 1, cur = 2;
    for (int i = 3; i <= n; i++) { int next = prev + cur; prev = cur; cur = next; }
    return cur;
}
```

**Complexity:** O(n) time, O(1) space. This is the gateway DP problem — recognizing the overlapping-subproblem recurrence is the key insight.

**Approach:** DP. At each house you either skip it (carry the previous best) or rob it (its value plus the best up to two houses back). Track the best 'including' and 'excluding' the previous house with two rolling variables.

```csharp
public int Rob(int[] nums) {
    int prev = 0, cur = 0; // best up to i-2 and i-1
    foreach (var n in nums) {
        int next = Math.Max(cur, prev + n);
        prev = cur; cur = next;
    }
    return cur;
}
```

**Complexity:** O(n) time, O(1) space. The recurrence dp[i] = max(dp[i-1], dp[i-2] + nums[i]) captures the 'no two adjacent' constraint.
